attempt_2_commands:
cp -p /etc/fstab /etc/fstab.bak-$(date +%s); awk 'BEGIN{OFS=FS} { if ($1 ~ /^#/) {print; next} if ($2=="/boot" && !/nosuid/) { if ($4=="") $4="nosuid"; else $4=$4",nosuid" } print }' /etc/fstab > /tmp/fstab_new; mv /tmp/fstab_new /etc/fstab; awk 'BEGIN{OFS=FS}
{ if ($1 ~ /^#/) {print; next}
  if ($2=="/boot") {
    if ($4 !~ /(^|,)(nosuid)(,|$)/) {
      $4=$4==""?"nosuid":$4",nosuid"
    }
    if ($6 !~ /^[0-9]+$/) {
      $6="0"
    }
  }
  print
}' /etc/fstab > /tmp/fstab_new; mv /tmp/fstab_new /etc/fstab
